# Data models module - base classes for domain entities

@abstract
class Entity:
    id: int

    def __init__(self, entity_id: int):
        self.id = entity_id

    @virtual
    def get_display_name(self) -> str:
        return f"Entity({self.id})"

class Person(Entity):
    first_name: str
    last_name: str

    def __init__(self, person_id: int, first: str, last: str):
        super().__init__(person_id)
        self.first_name = first
        self.last_name = last

    @override
    def get_display_name(self) -> str:
        return f"{self.first_name} {self.last_name}"

