# Services module - business logic that operates on models

from models import Entity, Person

class Repository:
    entities: list[Entity]

    def __init__(self):
        self.entities = []

    def add(self, entity: Entity):
        self.entities.append(entity)

    def find_by_id(self, search_id: int) -> Entity?:
        for entity in self.entities:
            if entity.id == search_id:
                return Some(entity)
        return None()

    def get_all_display_names(self) -> list[str]:
        return [e.get_display_name() for e in self.entities]

class PersonFormatter:
    @static
    def format_full(person: Person) -> str:
        return f"Person: {person.get_display_name()}"

    @static
    def format_with_id(person: Person) -> str:
        return f"[{person.id}] {person.first_name} {person.last_name}"
